import scala.collection.mutable

/**
 * Johnson's algorithm for all-pairs shortest paths.
 */
object Johnson {
  case class Edge(src: Int, dest: Int, weight: Int)

  def johnson(numVertices: Int, edges: List[Edge]): Option[Map[Int, Map[Int, Double]]] = {
    // Add virtual node
    val allEdges = edges ++ (0 until numVertices).map(i => Edge(numVertices, i, 0))

    // Bellman-Ford from virtual node
    val h = Array.fill(numVertices + 1)(Double.PositiveInfinity)
    h(numVertices) = 0.0

    for (_ <- 0 until numVertices) {
      for (e <- allEdges) {
        if (h(e.src) != Double.PositiveInfinity && h(e.src) + e.weight < h(e.dest)) {
          h(e.dest) = h(e.src) + e.weight
        }
      }
    }

    for (e <- allEdges) {
      if (h(e.src) != Double.PositiveInfinity && h(e.src) + e.weight < h(e.dest)) {
        return None // Negative cycle
      }
    }

    // Reweight edges
    val adjList = mutable.Map[Int, mutable.ListBuffer[(Int, Int)]]()
    for (i <- 0 until numVertices) adjList(i) = mutable.ListBuffer()
    for (e <- edges) {
      val newWeight = (e.weight + h(e.src) - h(e.dest)).toInt
      adjList(e.src) += ((e.dest, newWeight))
    }

    // Run Dijkstra from each vertex
    val result = mutable.Map[Int, Map[Int, Double]]()
    for (u <- 0 until numVertices) {
      val dist = dijkstraHelper(numVertices, adjList.toMap.map { case (k, v) => k -> v.toList }, u)
      val distances = (0 until numVertices).map { v =>
        if (dist(v) == Double.PositiveInfinity) v -> Double.PositiveInfinity
        else v -> (dist(v) - h(u) + h(v))
      }.toMap
      result(u) = distances
    }

    Some(result.toMap)
  }

  private def dijkstraHelper(n: Int, adjList: Map[Int, List[(Int, Int)]], src: Int): Array[Double] = {
    val dist = Array.fill(n)(Double.PositiveInfinity)
    val visited = Array.fill(n)(false)
    dist(src) = 0.0

    for (_ <- 0 until n) {
      var u = -1
      var minDist = Double.PositiveInfinity
      for (i <- 0 until n) {
        if (!visited(i) && dist(i) < minDist) {
          minDist = dist(i)
          u = i
        }
      }
      if (u == -1) return dist
      visited(u) = true

      for ((v, w) <- adjList.getOrElse(u, List.empty)) {
        if (!visited(v) && dist(u) + w < dist(v)) {
          dist(v) = dist(u) + w
        }
      }
    }
    dist
  }

  def main(args: Array[String]): Unit = {
    val edges = List(Edge(0,1,1), Edge(1,2,2), Edge(2,3,3), Edge(0,3,10))
    johnson(4, edges) match {
      case Some(result) =>
        for ((u, distances) <- result.toList.sortBy(_._1))
          println(s"From $u: $distances")
      case None => println("Negative cycle detected")
    }
  }
}

/// Johnson's algorithm for all-pairs shortest paths.
func johnson(_ numVertices: Int, _ edges: [[Int]]) -> String {
    let rawResult = johnson(numVertices: numVertices, edges: edges)
    if let text = rawResult as? String {
        return text
    }
    guard let distances = rawResult as? [Int: [Int: Double]] else {
        return String(describing: rawResult)
    }

    return distances.keys.sorted().flatMap { source in
        (distances[source] ?? [:]).keys.sorted().map { target in
            let value = distances[source]?[target] ?? Double.infinity
            if value == Double.infinity {
                return "Infinity"
            }
            if value == value.rounded() {
                return String(Int(value))
            }
            return String(value)
        }
    }.joined(separator: " ")
}

func johnson(numVertices: Int, edges: [[Int]]) -> Any {
    // Add virtual node
    var allEdges = edges
    for i in 0..<numVertices {
        allEdges.append([numVertices, i, 0])
    }

    // Bellman-Ford from virtual node
    var h = [Double](repeating: Double.infinity, count: numVertices + 1)
    h[numVertices] = 0

    for _ in 0..<numVertices {
        for e in allEdges {
            if h[e[0]] != Double.infinity && h[e[0]] + Double(e[2]) < h[e[1]] {
                h[e[1]] = h[e[0]] + Double(e[2])
            }
        }
    }

    for e in allEdges {
        if h[e[0]] != Double.infinity && h[e[0]] + Double(e[2]) < h[e[1]] {
            return "negative_cycle"
        }
    }

    // Reweight edges
    var adjList = [Int: [(Int, Int)]]()
    for i in 0..<numVertices { adjList[i] = [] }
    for e in edges {
        let newWeight = Int(Double(e[2]) + h[e[0]] - h[e[1]])
        adjList[e[0]]!.append((e[1], newWeight))
    }

    // Run Dijkstra from each vertex
    var result = [Int: [Int: Double]]()
    for u in 0..<numVertices {
        let dist = dijkstraHelper(n: numVertices, adjList: adjList, src: u)
        var distances = [Int: Double]()
        for v in 0..<numVertices {
            if dist[v] == Double.infinity {
                distances[v] = Double.infinity
            } else {
                distances[v] = dist[v] - h[u] + h[v]
            }
        }
        result[u] = distances
    }

    return result
}

func dijkstraHelper(n: Int, adjList: [Int: [(Int, Int)]], src: Int) -> [Double] {
    var dist = [Double](repeating: Double.infinity, count: n)
    var visited = [Bool](repeating: false, count: n)
    dist[src] = 0

    for _ in 0..<n {
        var u = -1
        var minDist = Double.infinity
        for i in 0..<n {
            if !visited[i] && dist[i] < minDist {
                minDist = dist[i]
                u = i
            }
        }
        if u == -1 { break }
        visited[u] = true

        for (v, w) in adjList[u] ?? [] {
            if !visited[v] && dist[u] + Double(w) < dist[v] {
                dist[v] = dist[u] + Double(w)
            }
        }
    }
    return dist
}

